def token_f1(a, b):
    sa = set(a.split())
    sb = set(b.split())
    if not sa or not sb:
        return 0.0
    tp = len(sa & sb)
    precision = tp / len(sa)
    recall = tp / len(sb)
    if precision+recall==0:
        return 0.0
    return 2*precision*recall/(precision+recall)
